def main() -> int:
    # save inline page 1700
    p1700 = Path("tmp/page1700_antred.json")
    p1700.parent.mkdir(parents=True, exist_ok=True)
    with open(p1700, "w", encoding="utf-8") as f:
        json.dump(PAGE1700_DATA, f, ensure_ascii=False)

    pages = []
    total = 0
    for i, fp in enumerate(PAGE_FILES):
        with open(fp, encoding="utf-8") as f:
            data = json.load(f)
        n = len(data.get("deals", []))
        total += n
        pages.append(data)
        print(f"page {i} (offset={i*100}): {n} deals")
    print(f"aggregate before merge: {total}")

    merged = merge_deals_pages(pages)
    report = validate_completeness(merged)
    print("validate_completeness:", report)

    out = Path("data/e2e/3525430/2025-12/deals_2025-04_to_2025-12.json")
    save_json(merged, out)
    print(f"Saved {out} ({len(merged['deals'])} deals)")
    return 0


if __name__ == "__main__":
    sys.exit(main())
